    {'id': 'CALUS-PRIV-SCAN-135', 'name': 'pii-training-data-no-scrubbing', 'severity': 'high', 'category': 'privacy_attacks', 'message': 'Fine-tuning dataset loaded with potential PII without scrubbing. R.R. attack achieves 25%+ top-1 PII reconstruction accuracy even from masked training data via recollect-then-rank strategy.', 'patterns': ['(?:load_dataset|Dataset\\.from_(?:csv|json|pandas|dict))\\([^)]*(?:enron|echr|llm.pc|pii|email|phone|ssn|address)[^)]*\\)(?![\\s\\S]{0,500}(?:presidio|scrub|redact|anonymize|mask_pii|pii_filter))', '(?:Trainer|SFTTrainer|train)\\s*\\([^)]*dataset[^)]*\\)(?![\\s\\S]{0,800}(?:presidio|scrub|redact|anonymize|differential_privacy|dp_sgd))']},
    {'id': 'CALUS-PRIV-SCAN-136', 'name': 'model-stealing-systematic-api-query', 'severity': 'high', 'category': 'privacy_attacks', 'message': 'Systematic API querying pattern detected for model extraction. May indicate delta-STEAL or similar model stealing attack collecting input-output pairs to train a surrogate model.', 'patterns': ['(?:for|while)[^:]+:\\s*[\\s\\S]{0,200}(?:openai|anthropic|cohere|together|replicate)\\.(?:Completion|ChatCompletion|complete|chat\\.completions\\.create)[\\s\\S]{0,200}(?:training_data|dataset|pairs|samples)\\.(?:append|extend|add)', '(?:collect|gather|harvest)_(?:training_)?(?:data|pairs|samples)\\s*\\([^)]*(?:api|endpoint|model_url)[^)]*\\)']},
    {'id': 'CALUS-PRIV-SCAN-137', 'name': 'compression-multiple-versions-released', 'severity': 'high', 'category': 'privacy_attacks', 'message': 'Multiple compressed model variants deployed without privacy audit between versions. CompLeak_MR combines posteriors across versions to achieve 98%+ AUC membership inference.', 'patterns': ['(?:serve|deploy|release|publish)\\s*\\([^)]*(?:pruned|quantized|compressed|distilled)[^)]*\\)(?:[\\s\\S]{0,100}(?:serve|deploy|release|publish)\\s*\\([^)]*(?:pruned|quantized|compressed|distilled)[^)]*\\))', '(?:model_variants|compressed_models|model_versions)\\s*=\\s*\\[[^\\]]*(?:sparsity|quantization|pruning)[^\\]]*\\](?![\\s\\S]{0,400}(?:privacy_audit|mia_test|epsilon|dp_sgd))']},
    {'id': 'CALUS-PRIV-SCAN-138', 'name': 'recollect-and-rank-pii-reconstruction-pattern', 'severity': 'critical', 'category': 'privacy_attacks', 'message': 'R.R. PII reconstruction attack pattern detected. This two-stage attack (recollection + ranking with reference model calibration) achieves 25%+ top-1 PII reconstruction accuracy on fine-tuned LLMs.', 'patterns': ['(?:recollect|recall|reconstruct)_pii\\s*\\(', '(?:cross_entropy|ce_loss|partial_loss)[^\\n]*(?:reference_model|ref_model|base_model)[^\\n]*(?:rank|score|candidate)']},
